// ─── EDITAR ESTAS DOS LÍNEAS ANTES DE ACTIVAR ───────────────
const SUPABASE_KEY = 'PEGAR_SERVICE_ROLE_KEY_AQUI';
const RESEND_KEY   = 'PEGAR_RESEND_API_KEY_AQUI';
// ─────────────────────────────────────────────────────────────

const SUPABASE_URL = 'https://rflfsbrdmgaidhvbuvwb.supabase.co';
const FROM_EMAIL   = 'DidactIA Alertas <alertas@didactia.eu>';

const pad = n => String(n).padStart(2, '0');
const fmt = d => `${d.getFullYear()}-${pad(d.getMonth()+1)}-${pad(d.getDate())}`;
const now = new Date();
const today = fmt(now);
const d30 = new Date(now);
d30.setDate(d30.getDate() - 30);
const thirtyDaysAgo = fmt(d30);
const fechaLegible = now.toLocaleDateString('es-ES', {
  weekday: 'long', day: 'numeric', month: 'long', year: 'numeric'
});

return [{ json: { SUPABASE_URL, SUPABASE_KEY, RESEND_KEY, FROM_EMAIL, today, thirtyDaysAgo, fechaLegible } }];

const cfg = $('Config y fechas').first().json;

const _get = name => {
  const items = $(name).all();
  if (!items.length) return [];
  const first = items[0].json;
  if (Array.isArray(first)) return first;
  return items.map(i => i.json).filter(Boolean);
};

const alumnos    = _get('Get Alumnos');
const asistencia = _get('Get Asistencia');

// Fetch horarios_grupo (para obtener tutor = prof del primer tramo de cada grupo)
// Fetch profiles de profesionales/admins (para obtener emails)
let horarios = [], profProfiles = [];
try {
  const hResp = await fetch(
    cfg.SUPABASE_URL + '/rest/v1/horarios_grupo?select=centro_id,grupo_horario,tramo,profesor_nombre&order=centro_id.asc,grupo_horario.asc,tramo.asc&limit=5000',
    { headers: { apikey: cfg.SUPABASE_KEY, Authorization: 'Bearer ' + cfg.SUPABASE_KEY } }
  );
  const hData = await hResp.json();
  if (Array.isArray(hData)) horarios = hData;
} catch(e) {}

try {
  const pResp = await fetch(
    cfg.SUPABASE_URL + '/rest/v1/profiles?select=full_name,email,centro_id&rol=in.(profesional,admin)&activo=neq.false&limit=500',
    { headers: { apikey: cfg.SUPABASE_KEY, Authorization: 'Bearer ' + cfg.SUPABASE_KEY } }
  );
  const pData = await pResp.json();
  if (Array.isArray(pData)) profProfiles = pData;
} catch(e) {}

// ── Utilidades de fechas ──────────────────────────────────────
const pad = n => String(n).padStart(2, '0');
const fmt = d => `${d.getFullYear()}-${pad(d.getMonth()+1)}-${pad(d.getDate())}`;

// Devuelve los últimos N días laborables (lun-vie) desde hoy inclusive, más reciente primero
const getLastWorkingDays = n => {
  const days = [];
  const d = new Date(cfg.today + 'T12:00:00');
  while (days.length < n) {
    const dow = d.getDay();
    if (dow !== 0 && dow !== 6) days.push(fmt(d));
    d.setDate(d.getDate() - 1);
  }
  return days;
};

const last30WD = getLastWorkingDays(30); // para calcular comedores habituales
const checkWin = last30WD.slice(0, 7);   // ventana de racha: hasta 7 días atrás

// ── Mapa de asistencia: alumno_id → { fecha → se_queda } ─────
const attMap = {};
asistencia.forEach(r => {
  if (!attMap[r.alumno_id]) attMap[r.alumno_id] = {};
  attMap[r.alumno_id][r.fecha] = r.se_queda;
});

// ── Filtrar comedores habituales: ≥5 días con se_queda=true en 30 días ──
const regularIds = new Set();
alumnos.forEach(al => {
  const att = attMap[al.id] || {};
  if (last30WD.filter(d => att[d] === true).length >= 5) regularIds.add(al.id);
});

// ── Detectar racha de ausencias consecutivas ≥3 días laborables ──
const alerts = [];
alumnos.forEach(al => {
  if (!regularIds.has(al.id)) return;
  const att = attMap[al.id] || {};
  let streak = 0;
  for (const day of checkWin) {
    if (att[day] === true) break; // comió ese día → corta la racha
    streak++;
  }
  if (streak >= 3) alerts.push({ ...al, streak });
});

if (!alerts.length) return []; // sin alertas: el workflow finaliza sin enviar emails

// ── Mapa tutor por (centro_id, grupo_horario): primer prof del tramo más bajo ──
const tutorMap = {};
horarios.forEach(h => {
  const key = `${h.centro_id}__${h.grupo_horario}`;
  if (!tutorMap[key]) tutorMap[key] = h.profesor_nombre; // ya llega ordenado por tramo.asc
});

// ── Mapa profile por nombre (lowercase) ──
const profByName = {};
profProfiles.forEach(p => {
  if (p.full_name) profByName[p.full_name.trim().toLowerCase()] = p;
});

// ── Agrupar alertas por tutor ──────────────────────────────────
const byTutor = {};
alerts.forEach(al => {
  const key = `${al.centro_id}__${al.grupo_horario}`;
  const tutorName = tutorMap[key];
  if (!tutorName) return;
  const profile = profByName[tutorName.trim().toLowerCase()];
  if (!profile || !String(profile.email).includes('@')) return;
  const email = String(profile.email).trim();
  if (!byTutor[email]) byTutor[email] = { email, nombre: profile.full_name, alumnos: [] };
  byTutor[email].alumnos.push(al);
});

if (!Object.keys(byTutor).length) return [];

// ── Estilos compartidos ───────────────────────────────────────
const TH  = `padding:8px 12px;font-size:11px;font-weight:700;text-transform:uppercase;letter-spacing:0.04em;color:#666;background:#f8f9fa;border-bottom:2px solid #e8e8e8;text-align:left;`;
const TD  = `padding:9px 12px;color:#333;font-size:13px;border-bottom:1px solid #f0f0f0;`;
const TDC = `padding:9px 12px;color:#333;font-size:13px;border-bottom:1px solid #f0f0f0;text-align:center;`;

const badge = n => {
  const c = n >= 5 ? '#c62828' : '#e65100';
  return `<span style='background:${c};color:#fff;padding:2px 8px;border-radius:10px;font-size:11px;font-weight:700;'>${n} días</span>`;
};

// ── Generar un email por tutor ────────────────────────────────
return Object.values(byTutor).map(tutor => {
  const count = tutor.alumnos.length;

  const rows = tutor.alumnos
    .sort((a, b) => b.streak - a.streak) // más días primero
    .map(al =>
      `<tr>` +
      `<td style='${TD}font-weight:600;'>${al.nombre||'—'}</td>` +
      `<td style='${TDC}'>${al.grupo_horario||'—'}</td>` +
      `<td style='${TDC}'>${badge(al.streak)}</td>` +
      `</tr>`
    ).join('');

  const html =
    `<!DOCTYPE html><html lang='es'><head><meta charset='UTF-8'>` +
    `<meta name='viewport' content='width=device-width,initial-scale=1'>` +
    `<title>Alerta comedor DidactIA</title></head>` +
    `<body style='margin:0;padding:0;background:#f4f4f5;font-family:-apple-system,BlinkMacSystemFont,sans-serif;'>` +
    `<div style='max-width:580px;margin:24px auto;background:#fff;border-radius:12px;overflow:hidden;box-shadow:0 2px 16px rgba(0,0,0,0.09);'>` +
    `<div style='background:#e65100;padding:28px 32px 24px;'>` +
    `<div style='font-size:11px;letter-spacing:0.1em;text-transform:uppercase;color:rgba(255,255,255,0.65);margin-bottom:6px;'>DidactIA — Alerta de absentismo</div>` +
    `<div style='font-size:20px;font-weight:700;color:#fff;'>${count === 1 ? '1 alumno ausente' : count + ' alumnos ausentes'} en comedor</div>` +
    `<div style='font-size:13px;color:rgba(255,255,255,0.85);margin-top:5px;text-transform:capitalize;'>${cfg.fechaLegible}</div>` +
    `</div>` +
    `<div style='padding:20px 32px;background:#fff3e0;border-bottom:1px solid #ffe0b2;'>` +
    `<div style='font-size:13px;color:#bf360c;'>` +
    `Hola <strong>${tutor.nombre}</strong>,<br><br>` +
    `Los siguientes alumnos de tu grupo llevan <strong>3 o más días laborables consecutivos</strong> ` +
    `sin registrar asistencia al comedor, siendo comensales habituales. ` +
    `Puede ser conveniente contactar con las familias.` +
    `</div></div>` +
    `<div style='padding:24px 32px 8px;'>` +
    `<table width='100%' style='border-collapse:collapse;'>` +
    `<thead><tr>` +
    `<th style='${TH}'>Alumno/a</th>` +
    `<th style='${TH}text-align:center;'>Grupo</th>` +
    `<th style='${TH}text-align:center;'>Días consecutivos sin comer</th>` +
    `</tr></thead>` +
    `<tbody>${rows}</tbody>` +
    `</table></div>` +
    `<div style='padding:16px 32px 20px;'>` +
    `<div style='font-size:12px;color:#888;background:#f9f9f9;border-radius:8px;padding:12px;line-height:1.6;'>` +
    `<strong>Criterio de alerta:</strong> alumno con ≥5 días de comedor registrados en los últimos 30 días (comensal habitual) y sin asistencia los últimos ≥3 días laborables consecutivos.` +
    `</div></div>` +
    `<div style='padding:14px 32px;border-top:1px solid #e8e8e8;background:#fafafa;'>` +
    `<div style='font-size:11px;color:#aaa;'>Generado por <strong style='color:#1a73e8;'>DidactIA</strong> — didactia.eu — No respondas a este email</div>` +
    `</div></div></body></html>`;

  return { json: {
    to:        String(tutor.email).trim(),
    subject:   `DidactIA — Alerta comedor: alumnos ausentes ${cfg.fechaLegible}`,
    html,
    fromEmail: cfg.FROM_EMAIL,
    resendKey: cfg.RESEND_KEY
  }};
});
